var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"급한 고비는 넘기셨대. 지금 막 안정을 되찾으셨어.","JPN":"ひとまず峠は越したって。ようやく容体が安定したみたい。","ENG":"He made it past the worst. You should be able to see him now.","TWN":"他們說爺爺已經渡過危險期，目前情況已經穩定下來。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"다행입니다.","JPN":"安心しました。","ENG":"Thank goodness.","TWN":"那就好。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"미안. 엉겁결에 요양원까지 따라오게 해버렸네.","JPN":"ごめん。結局老人ホームまでついてこさせちゃったね。","ENG":"I’m sorry. I somehow made you follow all the way here.","TWN":"不好意思，突然讓你一起跑來療養院。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 멋대로 쫓아왔을 뿐입니다.","JPN":"私が勝手についてきただけです。","ENG":"No need to be. I am the one who decided to come along.","TWN":"是我自己要跟過來的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그냥 따라온 것 치곤 굉장히 본격적으로 도와주고 있지 않아? 앞치마에 장갑까지……","JPN":"その割には、すごく本格的に手伝ってない？　エプロンに手袋まで……","ENG":"You’re doing way more than tagging along, though... Those gloves and apron...","TWN":"雖然你嘴上說是跟過來的，但你應該是認真要幫忙的吧？看你的圍裙跟手套……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공에겐 신세를 진 게 있으니까요. 마침 공원에서 먼산을 보는 것보다 생산적인 일이 필요했습니다.","JPN":"奈由香殿には借りがありますので。それに私には公園で遠くの山を見ているよりもやりがいのある仕事が必要でした。","ENG":"I owe you a lot, Mr. Nayuka. Also, this is more productive than sitting in the park and doing nothing.","TWN":"因為我欠你人情，而且與其坐在公園發呆，不如做些有建設性的事。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"공원에서 먼산을 보고 있었다고……?","JPN":"公園で遠くの山を……？","ENG":"You were sitting in the park, doing nothing...?","TWN":"你在公園發呆……？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그런데 뜻밖입니다. 나유카 공이 요양원에서 일을 돕고 계셨을 줄이야.","JPN":"それより、意外でした。奈由香殿が老人ホームでお仕事を手伝われていたとは。","ENG":"I must say that I am rather surprised. I did not know you were helping with the work here.","TWN":"不過真是意外，沒想到你會在療養院裡幫忙。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하하, 할아버지도 자주 볼 겸 요양원비도 벌고 좋잖아?","JPN":"はは、じいちゃんにもよく会えるし、お見舞いをしながら老人ホームの費用も稼げていいでしょ？","ENG":"Ha ha, I get to see my grandfather after all. Plus, they pay me.","TWN":"哈哈，這樣我可以常來看爺爺，還可以順便賺療養院的費用，不是很棒嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"솔직히 그날 이후로…… 할아버지와 떨어져 있는 것도 마음이 놓이지 않아서 말이야.","JPN":"正直あの日以来……じいちゃんと離れているのは不安でさ。","ENG":"To be honest... after what happened that day, I don’t feel comfortable leaving my grandfather alone.","TWN":"老實說，自從那天以後……我也不放心和爺爺分開。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"소중한 사람을 걱정하기에 그 곁을 지킨다는 거군요. 이해했습니다.","JPN":"大切な人が心配だから側で守りたいということですね。納得しました。","ENG":"You worry about your beloved ones, so you want to protect them. I understand.","TWN":"因為擔心重要的人，所以在他身旁守護嗎？我懂。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"NURSE_NPC_HOSPITAL_NULL","text":{"KOREA":"나나하라 씨. 물통 가져왔어.","JPN":"七原さん。バケツ持ってきたよ。","ENG":"Here’s the water you asked for, Miss Nanahara.","TWN":"七原，水桶拿來囉。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_10"},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"감사합니다. 그럼 왼쪽 복도부터 청소를 시작하겠습니다.","JPN":"ありがとうございます。それでは、左の廊下から掃除します。","ENG":"Thank you. I shall start cleaning the left corridor now.","TWN":"謝謝，那我從左邊的走廊開始打掃。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"난 오른쪽을 맡을게.","JPN":"僕は右を担当するよ。","ENG":"I’ll take the right, then.","TWN":"那我負責右邊。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"전보다 훨씬 깨끗해졌네. 어르신들도 좋아하겠다. 고생 많았어.","JPN":"前よりずっとキレイになったね。みんなも喜ぶよ。お疲れ様。","ENG":"It looks so much better. The elders would be pleased. Good work.","TWN":"整個煥然一新呢，長輩們應該會很開心吧，辛苦你囉。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그리 힘들진 않았습니다.","JPN":"そこまできつくはありませんでした。","ENG":"It was not hard work.","TWN":"沒有很辛苦。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그리고 이거.","JPN":"あと、これ。","ENG":"Oh, and take this.","TWN":"這給你。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이것은…… 돈입니다만? 왜 저에게 이런 걸 주시는지요?","JPN":"これは……お金？　どうして私にこれを？","ENG":"This is... money. Why are you paying me?","TWN":"這是……錢？為什麼要給我這個？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오늘 알바비의 절반이야. 같이 일했으니까 당연히 나누는 거지.","JPN":"今日のバイト代の半分。一緒に働いたんだから分けるのが当然だろ。","ENG":"It’s half of my paycheck for the day. You helped, so obviously you deserve half.","TWN":"這是今天打工薪水的一半，你也一起做事，薪水當然要平分囉。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"오해입니다. 저는 그저 나유카 공을 도왔을 뿐이니까요.","JPN":"いただけません。私はただ奈由香殿を手伝っただけですから。","ENG":"I did not mean to take money from you. I just wanted to help, that is all.","TWN":"你誤會了，我只是在幫你而已。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"괜찮아. 이러는 편이 내 마음이 편하거든.","JPN":"いいんだ。こうした方が僕も気が楽だし。","ENG":"I know. I just believe it’s better to do it this way.","TWN":"沒關係啦，這樣我心裡才過得去。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그리고, 난 치후유가 나에게 빚을 졌다고 생각하지 않아.","JPN":"それに、僕は千冬に貸しがあるなんて思ってないよ。","ENG":"Besides, I don’t think you owe me anything, Chifuyu.","TWN":"而且我不覺得你有欠我什麼。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"따지고 보면, 나도 내가 지키고 싶은 것들을 지키기 위해 너희들을 이용한 셈이니까.","JPN":"考えてみたら、僕も自分が守りたいものを守るために君たちを利用したわけだからね。","ENG":"If you think about it, I kind of used you to protect the people I love.","TWN":"硬要說的話，我也是因為有想守護的東西才會利用你們。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공……","JPN":"奈由香殿……","ENG":"Mr. Nayuka...","TWN":"南裕夏……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"으음……","JPN":"ううむ……","ENG":"Mm...","TWN":"嗯嗯……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"앗, 미안. 내가 불편하게 했나?","JPN":"あっ、ごめん。困らせちゃったかな？","ENG":"Ah, sorry. Did I make you feel uncomfortable?","TWN":"哎呀，抱歉，我讓你很尷尬嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아뇨, 이런 식으로 돈을 벌어본 적은 한 번도 없어서…… 어떻게 써야 할지 모르겠군요.","JPN":"いいえ、こういう風にお金を稼いだことは一度もなかったので……どう使ったらいいかわかりません。","ENG":"No, it is just that I never earned money this way... I do not know how to spend it.","TWN":"不是的，我沒有賺過錢……不知道該怎麼花。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"괜찮다면 이걸로 나유카 공과 조부님에게 식사를 대접해드리고 싶습니다만.","JPN":"よろしければこれで奈由香殿とお祖父様に食事をおもてなししたいのですが。","ENG":"If you do not mind, I would like to treat you and your grandfather.","TWN":"可以的話，我想拿來請你和爺爺吃飯。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"좋아. 그럼 시켜 먹는 것보단 내가 요리재료를 사올게. 원장님에게 부탁하면 주방정돈 쓰게 해 주실 거야.","JPN":"そっか。それじゃあ出前を取るより料理を作ろう。僕が材料を買ってくるよ。園長に頼めばキッチンくらいは貸してくれるさ。","ENG":"All right. Let’s cook for ourselves, though. The headmaster will let us use the kitchen.","TWN":"好啊，那別叫外賣，我去買食材回來。跟院長拜託一下應該可以借用廚房。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예? 그렇게 무리하실 필요는……","JPN":"はい？　そこまでなさる必要は……","ENG":"Huh? You don’t have to–","TWN":"嗯？你不需要這麼麻……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"기다리고 있어줘! 금방 다녀올 테니까!","JPN":"待ってて！　すぐ行ってくるから！","ENG":"Wait right here! I’ll be back soon!","TWN":"你等我！我很快就回來。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공은 자신의 힘에 대해 잘 모른다고 했지만……","JPN":"奈由香殿は自分の力についてよく知らないと言っていたが……","ENG":"Mr. Nayuka seemed unaware of his powers, but...","TWN":"雖然南裕夏不清楚自己本身的力量……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공의 조부님이라면…….","JPN":"奈由香殿のお祖父様なら……","ENG":"Maybe his grandfather...","TWN":"但要是他的爺爺……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"실례하겠습니다.","JPN":"失礼いたします。","ENG":"Excuse me.","TWN":"打擾了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"으음…… 누구십니까?","JPN":"ううむ……どちら様でしょうか。","ENG":"Hmm... May I ask who this is?","TWN":"嗯……你是誰？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"처음 뵙습니다. 나나하라 가문연합의 나나하라 치후유라고 합니다.","JPN":"お初にお目にかかります。七原家連合の七原千冬と申します。","ENG":"Pleasure to meet you. I am Nanahara Chifuyu from the Nanahara Family Alliance.","TWN":"初次見面您好，我是七原家族聯盟的七原千冬。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"나유카 켄지로라고 합니다. 이런 꼴로 뵙게 되어 송구스럽습니다.","JPN":"奈由香健次郎と申します。このような格好で申し訳ありません。","ENG":"I am Nayuka Kenjiro. Please excuse my unfit condition.","TWN":"我叫健次郎，這副模樣見客真是不好意思。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"어찌 그런 말씀을…… 손자인 나유카 공에게는 오히려 저희가 큰 도움을 받았습니다만.","JPN":"滅相もない……孫である奈由香殿にはむしろ私たちの方がたくさん助けていただいております。","ENG":"No, it is I who should be excused... Your grandson, Mr. Nayuka was of big help to us.","TWN":"您別這麼說……您的孫子南裕夏幫我們很多忙呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"……그렇습니까?","JPN":"……そうですか？","ENG":"...Is that so?","TWN":"……是嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"미나토는 아무 일도 없었다고 했지만, 역시 나나하라 가문과 접점이 있었던 모양이군요.","JPN":"湊は何事もなかったと言っておりましたが、やはり七原家と接点があったようですね。","ENG":"Minato claimed that he had nothing to do with the Alliance... But it seems that there was something between the Nanahara family and him.","TWN":"南裕夏雖然什麼都沒提，但他果然有和七原家族的人接觸呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예? 나유카 공이 조부님께 저희에 대해 아무 말도 하지 않은 겁니까?","JPN":"奈由香殿はお祖父様に私たちのことを何も話さなかったのですか？","ENG":"Huh? He didn’t tell you anything about what happened?","TWN":"什麼？他完全沒跟您提過我們的事嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"가문연합을 돕고자 한다면 목숨을 걸어야 한다, 그러니 연합을 떠나면 평화롭게 살 수 있으리라……","JPN":"連合を手伝おうとすれば命をかけなければならない、ならば連合から抜ければ平和に生きていけるはず……","ENG":"One must risk their own lives to help the Alliance. Therefore, it would be best to leave and live in peace...","TWN":"要幫助家族聯盟就必須把命都豁出去，因此離開聯盟才能平靜過日子……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"그것이 저희 집안의 생각이었기에, 저 또한 미나토에게 연합의 존재를 숨기고 큰일에 휘말리지 말라 가르쳤습니다.","JPN":"それが我が家の考えでしたので、私もまた湊に連合の存在を隠して大事に巻き込まれないようにしろと教えてまいりました。","ENG":"That was the mindset of our family. I hid everything about the Alliance from Minato, and told him to stay away from danger.","TWN":"這是我們家族的想法，所以我也對南裕夏隱瞞聯盟的存在，教他不要多管閒事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"그러니 미나토도 저를 위해 사실을 숨긴 것이겠지요.","JPN":"ですから湊も私のために事実を隠したのでしょう。","ENG":"I assume he hid everything for my own sake.","TWN":"他是因為這樣才隱瞞我的吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만…… 조부님께선 제 이름을 듣고도 뜻밖이라는 기색은 아니시더군요.","JPN":"しかし……お祖父様は私の名を聞いても意外な様子には見えませんでしたが。","ENG":"But... You did not look surprised when you heard my name, sir.","TWN":"不過……您聽到我的名字時，並未露出驚訝之情。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"이렇게 될 거라고, 어렴풋이 짐작은 하고 있었습니다.","JPN":"こうなると、うすうす思ってはおりました。","ENG":"I thought it was only a matter of time before something happened.","TWN":"因為我有預感這一天一定會到來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"미나토가 자신을 오오가미 마사키라 소개하는 친구를 데려왔을 때부터였지요.","JPN":"湊が大神雅紀と名乗る友達を連れてきた時からです。","ENG":"It all started when Minato brought a friend called Ogami Masaki.","TWN":"在他帶那位叫大神雅紀的朋友過來時，我就知道會有這麼一天。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 사람이 가문연합의 사람이란 것을…… 알고 계셨습니까?","JPN":"その人が連合の一員であるということを……ご存じだったのですか？","ENG":"So you knew... that he was part of the Alliance.","TWN":"您知道那個人是家族聯盟的人嗎……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"치후유님.","JPN":"千冬様。","ENG":"Miss Chifuyu.","TWN":"千冬。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"돌이켜보면 참 한심하지만, 저에겐 가문연합을 잊는 게 가문을 지키기 위한 길이라고 믿던 때가 있었습니다.","JPN":"振り返ってみると何とも情けないのですが、私には連合を忘れることが家を守る道であると信じていた頃がありました。","ENG":"As much as I am ashamed to admit so, there was a time when I believed that running away from the Alliance was the way to protect my family.","TWN":"說起來丟臉，但我曾相信，忘掉家族聯盟才是守護家族唯一的路。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"그래서 저는 제 자식을 어떤 불화에도 얽매이지 않게 하려고, 연합의 의무를 숨긴 채 행복하기만을 바랐습니다.","JPN":"息子がトラブルに巻き込まれないように連合の義務を隠し、ただ幸せに暮してほしいと願いました。","ENG":"I turned away from my duties in the Alliance and concealed everything from my children, blindly hoping and waiting for happiness.","TWN":"我不想我兒子捲入任何危險之中，我隱瞞聯盟的義務，希望他可以幸福過日子。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"하지만 그게 잘못된 결정이라는 걸 깨달았을 땐, 제 자식과 며느리를 잃은 뒤였습니다.","JPN":"ですが、息子と嫁をなくして初めて、それが間違った決定であったと悟ったのです。","ENG":"It was only after I had lost my son and daughter-in-law that I realized what I did was foolish.","TWN":"但當我發現這是個錯誤的決定時，我已經失去我的兒子和媳婦。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그 말씀은…… 나유카 공의 부모님께 변고가 있었다는 건가요?","JPN":"奈由香殿のご両親に何かあったのですか？","ENG":"Does that mean... that Mr. Nayuka’s parents passed away?","TWN":"您是指……南裕夏的父母親嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"가족이 함께 침식사태에 휘말렸습니다.","JPN":"家族全員が侵食事態に巻き込まれました。","ENG":"We were caught up in a Corruption disaster.","TWN":"他們一家捲入侵蝕事件當中，"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"뒤늦은 제가 구할 수 있었던 건 어린 미나토 뿐이었지요.","JPN":"遅れた私が助けられたのは幼い湊だけでした。","ENG":"Young Minato was the only one I could save.","TWN":"等我到的時候，只來得及救出小小的南裕夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"두 분은…… 침식체에게 당했군요.","JPN":"お二人は……侵食体にやられたのですね。","ENG":"His parents... were killed by C.O.s.","TWN":"他們二位……遇難了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"고작 작은 1종 침식체 한 마리였습니다.","JPN":"小さな第1種侵食体が1体。たったそれだけでした。","ENG":"It was a single Category 1 C.O. that killed them.","TWN":"不過是區區一隻1類侵蝕體，"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"하지만…… 제 자식은 침식체에 맞서는 법을 몰랐습니다.","JPN":"ですが……息子は侵食体に立ち向かう方法を知らなかったのです。","ENG":"But... my son never learned how to fight against them.","TWN":"可是……我兒子卻無力抵抗侵蝕體。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"하다못해…… 제가 활을 다루는 법만이라도 가르쳤다면, 두 사람을 그렇게 허망하게 잃진 않았겠지요.","JPN":"せめて……息子に弓を扱う方法だけでも教えていたなら、二人をあのようにあっけなく失いはしなかったでしょう。","ENG":"If only I had taught him archery, at least... Then perhaps I wouldn’t have lost them in vain.","TWN":"要是我……有教我兒子怎麼射箭，我就不會失去他們二個。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그래서, 나유카 공을 가르치기로 하셨군요.","JPN":"それで、奈由香殿を教えることにしたのですね。","ENG":"So that is why you decided to teach Mr. Nayuka.","TWN":"於是您就決定要教南裕夏射箭嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"예. 늦은 후회였지만, 그 아이만큼은 잃고 싶지 않았으니까요.","JPN":"はい。いまさら後悔しても遅すぎますが、あの子だけは失いたくなかったのです。","ENG":"Yes. Some might call it late regret, but I didn’t want to lose him too.","TWN":"是，雖然是悔不當初，但我不想再失去他。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"하지만 미나토는 한동안 좌절에 빠져 아무것도 받아들이지 못했습니다. 어린 것이 눈앞에서 부모를 여의었으니 무리도 아니지요.","JPN":"ですが湊は長い間塞ぎ込んで、何も受け入れられませんでした。幼い子どもが目の前で親を亡くしたのですから無理もありません。","ENG":"Meanwhile, Minato was broken and had trouble moving on. I assume it’s only natural, witnessing the death of his parents at a young age.","TWN":"他有陣子很喪氣，什麼都不要。畢竟當時他還那麼小，就親眼目睹父母在眼前死去，也難怪他會這樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"하지만 오오가미란 친구를 만나면서 활기를 되찾기 시작했지요.","JPN":"しかし大神という友達に出会ってから元気を取り戻し始めました。","ENG":"But then, he met Ogami Masaki. He slowly regained his energy.","TWN":"不過自從他交了大神這個朋友後，就漸漸找回以往的活力。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"학교도 다시 다니고, 친구들도 사귈 만큼 밝아졌습니다.","JPN":"また学校に通い、友達も作れるほどに明るくなったのです。","ENG":"He went back to school and made new friends.","TWN":"他開始變得活潑起來，不僅回到學校，也開始結交朋友。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"세상을 등진 그 아이는…… 모순적이게도 가문연합의 사람 덕에 삶을 되찾은 겁니다.","JPN":"世に背を向けていたあの子は……皮肉にも連合の人のおかげで人生を取り戻しました。","ENG":"Such an irony it is... being saved by a member of the Family Alliance.","TWN":"他原本都把自己關在家裡，說起來有點諷刺……是家族聯盟的人讓那孩子恢復正常生活的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"그리던 어느 날, 미나토가 먼저 활을 쏘는 법을 배우고 싶다고 말하더군요.","JPN":"そんなある日、湊の方から弓を教わりたいと言い出しました。","ENG":"Then one day, Minato came to me asking if he could learn how to use a bow.","TWN":"然而某天，他自己先開口說想學射箭。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"스스로를 지키라고 가르쳤지만, 그 아이의 천성대로라면 분명 다른 사람들을 위해 그 힘을 썼을 겁니다.","JPN":"自分を守るためにと教えたのですが、あの子の性格ならきっと他の人たちのためにその力を使ったのでしょう。","ENG":"I taught him to protect no one other than himself. But with his altruistic nature, I believe he has been using them for others instead.","TWN":"雖然我教他是要他自保，但照那孩子的個性，一定會用來保護其他人的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예, 나유카 공은 그런 사람이니까요.","JPN":"はい、奈由香殿はそんな人ですから。","ENG":"Yes, Mr. Nayuka is that kind of person.","TWN":"是的，南裕夏就是這種人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"연합의 의무를 저버린 이 못난 늙은이를 용서하지 마십시오.","JPN":"連合の義務を忘れたこの愚かな老人をどうかお許しにならないでください。","ENG":"Do not forgive this fool old man for abandoning his duties.","TWN":"請不要原諒我這個背棄聯盟義務的糟老頭，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"그리고…… 미나토를 잘 부탁드립니다.","JPN":"それから……湊のことをよろしくお願いいたします。","ENG":"And… please take good care of Minato.","TWN":"還有……南裕夏就拜託你了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"그런데, 어쩐 일로 저를 찾아오신 건지 여쭤봐도 되겠습니까?","JPN":"ところで、どうして私を訪ねて来られたのかお伺いしてもよろしいでしょうか。","ENG":"May I ask on what occasion have you come to see me?","TWN":"不過，我可以問一下，你為何事而來的嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRAND_NPC_MINATO_FAMILY","text":{"KOREA":"이 늙은이에게 요구하실 것이 있다면 치후유님께 어떤 도움이라도 드리겠습니다.","JPN":"この老いぼれにできることでしたら、どんなことでもお手伝いいたしましょう。","ENG":"If there’s anything I could do to help, do let me know.","TWN":"要是有什麼事是我這個老頭幫得上忙的，我一定赴湯蹈火在所不辭。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아무것도 아닙니다. 우연히 기회가 닿아 찾아뵀을 뿐……","JPN":"何でもありません。偶然お伺いする機会があって来ただけで……","ENG":"Nothing. It was coincidence...","TWN":"沒事，只是剛好有這個機會可以來看您……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그럼 다음에 연이 닿게 되면 찾아뵙지요.","JPN":"それでは、また。","ENG":"But if fate allows it, hopefully we will see each other again.","TWN":"那就下次有機會再見囉。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"가르쳐주십시오.","JPN":"教えてください。","ENG":"Teach me.","TWN":"教我。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"벌써 나흘째입니다. 그만 돌아가시지요.","JPN":"もう4日目です。お帰りください。","ENG":"It has been four days already. Please go back.","TWN":"這已經是第三天了，您請回吧。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"검술을 배우고 싶습니다. 부탁드립니다.","JPN":"剣術を教わりたいのです。お願いします。","ENG":"I wish to learn from you. Please.","TWN":"我想學劍法，拜託你教我。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저는 검을 내려놓은 지 오래입니다. 그리고 영지 바깥에는 다른 좋은 스승들이 많지요.","JPN":"私は長いこと刀を振るっていません。それに領地の外には他にも師と仰ぐことのできる立派な方がたくさんおられます。","ENG":"I have long past stopped using my sword. There are many others outside the estate who will be a good teacher.","TWN":"我不拿劍很久了，而且領地外有很多比我更好的師父吧。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇게 충분히 설득했을 텐데, 어째서 계속 이곳을 찾아오시는 겁니까?","JPN":"そのように十分ご説明したはずですが、なぜ相も変わらず訪ねてこられるのですか？","ENG":"I thought I made it clear, why do you keep coming back?","TWN":"我都已經說成這樣了，您為何還是一直要來這裡呢？"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"연합의 어르신들은…… 당주님께 무슨 일이 생길 때를 예비해야 한다며, 제가 함부로 거친 일을 하지 못하게 합니다.","JPN":"連合の長老たちは……当主に何かあった時に備えよといいながら、私に危ない仕事をさせないようにします。","ENG":"The elders in the Alliance... they won’t let me do anything dangerous, in case something happens to Lady Nanahara.","TWN":"聯盟的長輩說……萬一堂主發生什麼事的話我要隨時預備，所以不讓我幹粗活兒。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"실로 합리적인 판단이지요. 나나하라 가문의 명맥이 끊어지는 일이 벌어져선 안 되니까요.","JPN":"実に合理的なご判断です。七原家の命脈がたたれることになってはいけませんから。","ENG":"Precisely. The Nanahara bloodline must be preserved under all circumstances.","TWN":"這是很合理的判斷，七原家族的命脈絕對不能斷。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"만일에 하나 지금의 나나하라 당주님께 변고가 생긴다면, 그때는 치후유님이 그 자릴 맡으셔야 합니다.","JPN":"万が一にも今の七原家ご当主様に異変が生じたら、その時には千冬様がその役割を果たさなくてはいけないのです。","ENG":"Miss Chifuyu. If Lady Nanahara passes away for whatever cause, it will be you who will be filling in.","TWN":"萬一現任七原堂主真的發生什麼事，您就必須繼承那個位置。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"그건 싫습니다!","JPN":"それは嫌です！","ENG":"I don’t want to!","TWN":"我不要！"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"언니……, 당주님에게 나쁜 일이 생기는 건 상상도 하고 싶지 않습니다!","JPN":"姉上……当主に良からぬことが起きるなどとは想像もしたくありません！","ENG":"If anything happens to my sist–... Lady Nanahara, I mean...","TWN":"姊姊……我不願意想像堂主有發生任何意外的可能性。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"제가 지킬 겁니다! 당주님에게 그런 나쁜 일이 생기지 않도록 말입니다!","JPN":"私が守ります！　当主にそのようなことが起きないように！","ENG":"I will protect her! So that she would not be in any harm!","TWN":"我會保護她！我會保護堂主不發生任何事故！"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"하지만…… 지금의 저는 누군가를 지킬 힘도, 당주가 될 재능도 없습니다.","JPN":"ですが……今の私は誰かを守る力も、当主になる才能もありません。","ENG":"But... I lack both strength and wit. I cannot become either a warrior or a head.","TWN":"可是……現在的我，根本沒能力保護任何人，也沒條件當堂主。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"사나에님은 당주님을 지키기 위해 검술을 익히셨다고 들었습니다.","JPN":"早苗様は当主を守るために剣術を身につけたとお聞きしました。","ENG":"I heard that you practice swordsmanship to protect Lady Nanahara, Miss Sanae.","TWN":"我聽說早苗姊姊是為了保護堂主才學習劍法的。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"그러니…… 부디 배움을 허락해주십시오.","JPN":"ですので……どうか教えてください。","ENG":"So, please... Allow me to learn to walk your way.","TWN":"拜託你……讓我學吧！"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나나하라 가문이 하야미 사람과 접촉한다는 사실이 알려지면 치후유님의 입장이 곤란해지실 수도 있습니다.","JPN":"七原家が速水家の者と接触しているということが知られれば、千冬様の立場が難しくなるかもしれません。","ENG":"You might get into trouble if people notice that you were in touch with a Hayami, Miss Chifuyu.","TWN":"七原家族和速水家的人接觸一事要是傳出去的話，您恐怕會受到刁難。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"후회하지 않을 각오가 되어 있으십니까?","JPN":"後悔しない覚悟がおありなのですか？","ENG":"Are you sure you would not regret this?","TWN":"您確定您不會後悔嗎？"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_YOUNG","text":{"KOREA":"예, 후회하지 않을 것입니다.","JPN":"はい、後悔しません。","ENG":"No, I won't.","TWN":"是，我不後悔。"},"stage":{"bg":"NANAHARA2_01","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"당주님에게 도움이 되지 못하는 것만큼 후회될 일은 없을 테니까요.","JPN":"当主のお役に立てないことより後悔することなどないでしょうから。","ENG":"The only thing I would be regretting is not being of help to Lady Nanahara.","TWN":"沒有什麼事會比幫不上堂主更令我後悔。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"맞아요. 나유카 공은 소중한 사람들을 훌륭히 지켜 내셨습니다.","JPN":"そうです。奈由香殿は大切な人たちを立派に守り抜かれました。","ENG":"You are right. Mr. Nayuka protected his people with a strong will.","TWN":"沒錯，南裕夏確實很盡責地在保護他重視的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그에 비하면 저는 나약해서……","JPN":"それに比べ私は意気地がなく……","ENG":"Compared to him, I am weak...","TWN":"和他比起來，我還太軟弱……"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……당주님 한 분에게조차 의지가 되지 못하는군요.","JPN":"……当主お一人からも頼りにされていないのですね。","ENG":"...I am not even reliable to Lady Nanahara.","TWN":"……連要成為堂主一個人的倚靠都辦不到。"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"Hmm?","TWN":"這是……？"},"stage":{"bg":"CORRIDOR_02","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……침식 경보?","JPN":"……侵食警報？","ENG":"...A Corruption alert?","TWN":"……侵蝕警報？"},"stage":{"bg":"SKY","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};